 import { EventType, QueryInstance } from '../types';
+import { Relation } from '../../relation/types';
+import { $internal } from '../../common';
+
+function pairKey(relation: Relation, target: Entity): string {
+    return `${relation[$internal].trait.id}:${target}`;
+}
+
+function hasTrackedPair(group: QueryInstance['trackingGroups'][number], pair: any, eid: number): boolean {
+    const { relation, target } = pair[$internal];
+    const prefix = `${relation[$internal].trait.id}:`;
+    if (target === '*') {
+        for (const [key, entities] of group.pairTrackers) {
+            if (key.startsWith(prefix) && entities.has(eid)) return true;
+        }
+        return false;
+    }
+    return group.pairTrackers.get(pairKey(relation, target))?.has(eid) ?? false;
+}
+
+/** Record a relation-pair event and update the query's pair-aware tracking state. */
+export function checkQueryPairTracking(
+    world: World,
+    query: QueryInstance,
+    entity: Entity,
+    eventType: EventType,
+    relation: Relation,
+    target: Entity
+): boolean {
+    const eid = getEntityId(entity);
+    const key = pairKey(relation, target);
+
+    for (const group of query.trackingGroups) {
+        const matchesPair = group.relationPairs.some((pair) => {
+            const pairCtx = pair[$internal];
+            return pairCtx.relation === relation && (pairCtx.target === '*' || pairCtx.target === target);
+        });
+        if (!matchesPair) continue;
+
+        const tracked = group.pairTrackers.get(key);
+        if (group.type === eventType) {
+            (tracked ?? group.pairTrackers.set(key, new Set()).get(key)!).add(eid);
+        } else if (
+            (eventType === 'add' && (group.type === 'remove' || group.type === 'change')) ||
+            (eventType === 'remove' && (group.type === 'add' || group.type === 'change'))
+        ) {
+            tracked?.delete(eid);
+        }
+    }
+
+    return checkQueryTracking(world, query, entity, eventType, -1, 0);
+}
